   652 | ConstraintTy
   653 | ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
   654 |                               SmallVectorImpl<Value *> &NewVariables) const {
   655 |   assert(NewVariables.empty() && "NewVariables must be empty when passed in");
   656 |   bool IsEq = false;
   657 |   bool IsNe = false;
   658 | 
   659 |   // Try to convert Pred to one of ULE/SLT/SLE/SLT.
   660 |   switch (Pred) {
   661 |   case CmpInst::ICMP_UGT:
   662 |   case CmpInst::ICMP_UGE:
   663 |   case CmpInst::ICMP_SGT:
   664 |   case CmpInst::ICMP_SGE: {
   665 |     Pred = CmpInst::getSwappedPredicate(Pred);
   666 |     std::swap(Op0, Op1);
   667 |     break;
   668 |   }
   669 |   case CmpInst::ICMP_EQ:
   670 |     if (match(Op1, m_Zero())) {
   671 |       Pred = CmpInst::ICMP_ULE;
   672 |     } else {
   673 |       IsEq = true;
   674 |       Pred = CmpInst::ICMP_ULE;
   675 |     }
   676 |     break;
   677 |   case CmpInst::ICMP_NE:
   678 |     if (match(Op1, m_Zero())) {
   679 |       Pred = CmpInst::getSwappedPredicate(CmpInst::ICMP_UGT);
   680 |       std::swap(Op0, Op1);
   681 |     } else {
   682 |       IsNe = true;
   683 |       Pred = CmpInst::ICMP_ULE;
   684 |     }
   685 |     break;
   686 |   default:
   687 |     break;
   688 |   }
   689 | 
   690 |   if (Pred != CmpInst::ICMP_ULE && Pred != CmpInst::ICMP_ULT &&
   691 |       Pred != CmpInst::ICMP_SLE && Pred != CmpInst::ICMP_SLT)
   692 |     return {};
   693 | 
   694 |   SmallVector<ConditionTy, 4> Preconditions;
   695 |   bool IsSigned = CmpInst::isSigned(Pred);
   696 |   auto &Value2Index = getValue2Index(IsSigned);
   697 |   auto ADec = decompose(Op0->stripPointerCastsSameRepresentation(),
   698 |                         Preconditions, IsSigned, DL);
   699 |   auto BDec = decompose(Op1->stripPointerCastsSameRepresentation(),
   700 |                         Preconditions, IsSigned, DL);
   701 |   int64_t Offset1 = ADec.Offset;
   702 |   int64_t Offset2 = BDec.Offset;
   703 |   Offset1 *= -1;
   704 | 
   705 |   auto &VariablesA = ADec.Vars;
   706 |   auto &VariablesB = BDec.Vars;
   707 | 
   708 |   // First try to look up \p V in Value2Index and NewVariables. Otherwise add a
   709 |   // new entry to NewVariables.
   710 |   SmallDenseMap<Value *, unsigned> NewIndexMap;
   711 |   auto GetOrAddIndex = [&Value2Index, &NewVariables,
   712 |                         &NewIndexMap](Value *V) -> unsigned {
   713 |     auto V2I = Value2Index.find(V);
   714 |     if (V2I != Value2Index.end())
   715 |       return V2I->second;
   716 |     auto Insert =
   717 |         NewIndexMap.insert({V, Value2Index.size() + NewVariables.size() + 1});
   718 |     if (Insert.second)
   719 |       NewVariables.push_back(V);
   720 |     return Insert.first->second;
   721 |   };
   722 | 
   723 |   // Make sure all variables have entries in Value2Index or NewVariables.
   724 |   for (const auto &KV : concat<DecompEntry>(VariablesA, VariablesB))
   725 |     GetOrAddIndex(KV.Variable);
   726 | 
   727 |   // Build result constraint, by first adding all coefficients from A and then
   728 |   // subtracting all coefficients from B.
   729 |   ConstraintTy Res(
   730 |       SmallVector<int64_t, 8>(Value2Index.size() + NewVariables.size() + 1, 0),
   731 |       IsSigned, IsEq, IsNe);
   732 |   // Collect variables that are known to be positive in all uses in the
   733 |   // constraint.
   734 |   SmallDenseMap<Value *, bool> KnownNonNegativeVariables;
   735 |   auto &R = Res.Coefficients;
   736 |   for (const auto &KV : VariablesA) {
   737 |     R[GetOrAddIndex(KV.Variable)] += KV.Coefficient;
   738 |     auto I =
   739 |         KnownNonNegativeVariables.insert({KV.Variable, KV.IsKnownNonNegative});
   740 |     I.first->second &= KV.IsKnownNonNegative;
   741 |   }
   742 | 
   743 |   for (const auto &KV : VariablesB) {
   744 |     if (SubOverflow(R[GetOrAddIndex(KV.Variable)], KV.Coefficient,
   745 |                     R[GetOrAddIndex(KV.Variable)]))
   746 |       return {};
   747 |     auto I =
   748 |         KnownNonNegativeVariables.insert({KV.Variable, KV.IsKnownNonNegative});
   749 |     I.first->second &= KV.IsKnownNonNegative;
   750 |   }
   751 | 
   752 |   int64_t OffsetSum;
   753 |   if (AddOverflow(Offset1, Offset2, OffsetSum))
   754 |     return {};
   755 |   if (Pred == (IsSigned ? CmpInst::ICMP_SLT : CmpInst::ICMP_ULT))
   756 |     if (AddOverflow(OffsetSum, int64_t(-1), OffsetSum))
   757 |       return {};
   758 |   R[0] = OffsetSum;
   759 |   Res.Preconditions = std::move(Preconditions);
   760 | 
